1657	fn run_remote_trigger(input: RemoteTriggerInput) -> Result<String, String> {
1658	    let method = input.method.unwrap_or_else(|| "GET".to_string());
1659	    let client = Client::new();
1660	
1661	    let mut request = match method.to_uppercase().as_str() {
1662	        "GET" => client.get(&input.url),
1663	        "POST" => client.post(&input.url),
1664	        "PUT" => client.put(&input.url),
1665	        "DELETE" => client.delete(&input.url),
1666	        "PATCH" => client.patch(&input.url),
1667	        "HEAD" => client.head(&input.url),
1668	        other => return Err(format!("unsupported HTTP method: {other}")),
1669	    };
1670	
1671	    // Apply custom headers
1672	    if let Some(ref headers) = input.headers {
1673	        if let Some(obj) = headers.as_object() {
1674	            for (key, value) in obj {
1675	                if let Some(val) = value.as_str() {
1676	                    request = request.header(key.as_str(), val);
1677	                }
1678	            }
1679	        }
1680	    }
1681	
1682	    // Apply body
1683	    if let Some(ref body) = input.body {
1684	        request = request.body(body.clone());
1685	    }
1686	
1687	    // Execute with a 30-second timeout
1688	    let request = request.timeout(Duration::from_secs(30));
1689	
1690	    match request.send() {
1691	        Ok(response) => {
1692	            let status = response.status().as_u16();
1693	            let body = response.text().unwrap_or_default();
1694	            let truncated_body = if body.len() > 8192 {
1695	                format!(
1696	                    "{}\n\n[response truncated — {} bytes total]",
1697	                    &body[..8192],
1698	                    body.len()
1699	                )
1700	            } else {
1701	                body
1702	            };
1703	            to_pretty_json(json!({
1704	                "url": input.url,
1705	                "method": method,
1706	                "status_code": status,
1707	                "body": truncated_body,
1708	                "success": status >= 200 && status < 300
1709	            }))
1710	        }
1711	        Err(e) => to_pretty_json(json!({
1712	            "url": input.url,
1713	            "method": method,
1714	            "error": e.to_string(),
1715	            "success": false
1716	        })),
