199	        let builtin_specs = mvp_tool_specs();
200	        let canonical_names = builtin_specs
201	            .iter()
202	            .map(|spec| spec.name.to_string())
203	            .chain(
204	                self.plugin_tools
205	                    .iter()
206	                    .map(|tool| tool.definition().name.clone()),
207	            )
208	            .chain(self.runtime_tools.iter().map(|tool| tool.name.clone()))
209	            .collect::<Vec<_>>();
210	        let mut name_map = canonical_names
211	            .iter()
212	            .map(|name| (normalize_tool_name(name), name.clone()))
213	            .collect::<BTreeMap<_, _>>();
214	
215	        for (alias, canonical) in [
216	            ("read", "read_file"),
217	            ("write", "write_file"),
218	            ("edit", "edit_file"),
219	            ("glob", "glob_search"),
220	            ("grep", "grep_search"),
221	        ] {
222	            name_map.insert(alias.to_string(), canonical.to_string());
223	        }
224	
225	        let mut allowed = BTreeSet::new();
226	        for value in values {
227	            for token in value
