3362	fn classify_lane_failure(error: &str) -> LaneFailureClass {
3363	    let normalized = error.to_ascii_lowercase();
3364	
3365	    if normalized.contains("prompt") && normalized.contains("deliver") {
3366	        LaneFailureClass::PromptDelivery
3367	    } else if normalized.contains("trust") {
3368	        LaneFailureClass::TrustGate
3369	    } else if normalized.contains("branch")
3370	        && (normalized.contains("stale") || normalized.contains("diverg"))
3371	    {
3372	        LaneFailureClass::BranchDivergence
3373	    } else if normalized.contains("gateway") || normalized.contains("routing") {
3374	        LaneFailureClass::GatewayRouting
3375	    } else if normalized.contains("compile")
3376	        || normalized.contains("build failed")
3377	        || normalized.contains("cargo check")
3378	    {
3379	        LaneFailureClass::Compile
3380	    } else if normalized.contains("test") {
3381	        LaneFailureClass::Test
3382	    } else if normalized.contains("tool failed")
3383	        || normalized.contains("runtime tool")
3384	        || normalized.contains("tool runtime")
3385	    {
3386	        LaneFailureClass::ToolRuntime
3387	    } else if normalized.contains("plugin") {
3388	        LaneFailureClass::PluginStartup
3389	    } else if normalized.contains("mcp") && normalized.contains("handshake") {
3390	        LaneFailureClass::McpHandshake
3391	    } else if normalized.contains("mcp") {
3392	        LaneFailureClass::McpStartup
3393	    } else {
3394	        LaneFailureClass::Infra
3395	    }
3396	}
